const a = [
  {"id":2758,"text":"Which of the following is the most common cause of pyogenic osteomyelitis?","explanation":"The most common cause of **pyogenic osteomyelitis** is ***Staphylococcus aureus***. This bacterium is responsible for a significant majority of cases, especially in otherwise healthy individuals.\r\n\r\n---\r\n\r\n*Salmonella typhi* is commonly associated with typhoid fever; it can cause osteomyelitis in patients with sickle cell disease.\r\n\r\n*Pseudomonas aeruginosa* can cause osteomyelitis, particularly in individuals with compromised immune systems or those with puncture wounds.\r\n\r\n*Mycobacterium tuberculosis* causes tuberculous osteomyelitis, which is different from pyogenic osteomyelitis.\r\n\r\n*Staphylococcus epidermidis* is a less virulent organism; it is more commonly associated with prosthetic joint infections rather than primary osteomyelitis.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1195.","responses":[{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false},{"text":"Staphylococcus epidermidis","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":true,"visible":false},{"text":"Salmonella typhi","correct":false,"visible":false}]},{"id":5197,"text":"Which of the following bacteria causes botulism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 380.","responses":[{"text":"Clostridium tetani","correct":false,"visible":false},{"text":"Clostridium botulinum","correct":true,"visible":false},{"text":"Clostridium perfringens","correct":false,"visible":false},{"text":"Clostridium difficile","correct":false,"visible":false},{"text":"Clostridium septicum","correct":false,"visible":false}]},{"id":5203,"text":"Which of the following is not a function of non-steroidal anti-inflammatory drugs (NSAIDs)?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 498.","responses":[{"text":"They inhibit 5-lipoxygenase enzyme activity","correct":true,"visible":false},{"text":"Aspirin acetylates cyclooxygenase irreversibly","correct":false,"visible":false},{"text":"They inhibit cyclooxygenase-1 (COX-1) enzyme activity","correct":false,"visible":false},{"text":"They inhibit cyclooxygenase-2 (COX-2) enzyme activity","correct":false,"visible":false},{"text":"They inhibit prostaglandin synthesis","correct":false,"visible":false}]},{"id":5236,"text":"Which of the following arteries gives rise to the nutrient artery of the fibula?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 761.","responses":[{"text":"Inferior medial genicular artery","correct":false,"visible":false},{"text":"Anterior tibial artery","correct":false,"visible":false},{"text":"Posterior tibial artery","correct":false,"visible":false},{"text":"Peroneal artery","correct":true,"visible":false},{"text":"Popliteal artery","correct":false,"visible":false}]},{"id":5242,"text":"Which of the following muscles pass through the greater sciatic foramen?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 568.","responses":[{"text":"Obturator internus","correct":false,"visible":false},{"text":"Superior and inferior gemelli","correct":false,"visible":false},{"text":"Piriformis","correct":true,"visible":false},{"text":"Quadratus femoris","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false}]},{"id":5246,"text":"Which of the following types of collagen is most abundant in bone tissue?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 48.","responses":[{"text":"Collagen type IX","correct":false,"visible":false},{"text":"Collagen type XI","correct":false,"visible":false},{"text":"Collagen type II","correct":false,"visible":false},{"text":"Collagen type I","correct":true,"visible":false},{"text":"Collagen type V","correct":false,"visible":false}]},{"id":5250,"text":"Which of the following muscles inserts onto the trochanteric fossa?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 723.","responses":[{"text":"Adductor longus","correct":false,"visible":false},{"text":"Adductor brevis","correct":false,"visible":false},{"text":"Quadratus femoris","correct":false,"visible":false},{"text":"Obturator internus","correct":true,"visible":false},{"text":"Gluteus maximus","correct":false,"visible":false}]},{"id":5256,"text":"What are the contents of the femoral sheath from the lateral to the medial side?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710.","responses":[{"text":"Femoral nerve, femoral artery, femoral vein, and the inguinal lymph nodes","correct":false,"visible":false},{"text":"Femoral nerve, femoral artery, and the femoral vein","correct":false,"visible":false},{"text":"Femoral artery, femoral vein, and the lymphatic vessels","correct":true,"visible":false},{"text":"Femoral vein, femoral artery, and the lymphatic vessels","correct":false,"visible":false},{"text":"Femoral vein, femoral artery, and the femoral nerve","correct":false,"visible":false}]},{"id":5265,"text":"Which of the following structures are present in the femoral canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"Lymphatic vessels and sometimes deep inguinal lymph nodes","correct":true,"visible":false},{"text":"Femoral vein","correct":false,"visible":false},{"text":"Femoral artery, vein, and the lymphatic vessels","correct":false,"visible":false},{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false}]},{"id":5270,"text":"Which of the following stores calcium?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 291.","responses":[{"text":"Rough endoplasmic reticulum","correct":false,"visible":false},{"text":"Sarcolemma","correct":false,"visible":false},{"text":"Sarcoplasm","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false},{"text":"Sarcoplasmic reticulum","correct":true,"visible":false}]},{"id":5277,"text":"The femoral sheath is formed by which of the following layers of fascia?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"The processes vaginalis","correct":false,"visible":false},{"text":"the pectineus fascia","correct":false,"visible":false},{"text":"The fascia iliaca and fascia transversalis","correct":true,"visible":false},{"text":"The psoas fascia and the fatty layer of the superficial fascia","correct":false,"visible":false},{"text":"The fascia lata and the membranous layer of the superficial fascia","correct":false,"visible":false}]},{"id":5351,"text":"Which of the following muscles is a lateral rotator of the upper limb and attaches to the greater tubercle of the humerus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 706.","responses":[{"text":"Infraspinatus","correct":true,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false}]},{"id":5352,"text":"Which of the following muscles attach to the lesser tubercle of the humerus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 692.","responses":[{"text":"Subscapularis","correct":true,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Infraspinatus","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false}]},{"id":5353,"text":"Which of the following is the longest muscle in the human body?","explanation":"The **longest muscle** in the human body is the **sartorius muscle**. It runs diagonally across the thigh, originating from the anterior superior iliac spine and inserting into the medial side of the tibia. The sartorius is involved in flexing, abducting, and laterally rotating the thigh at the hip joint, as well as flexing the knee.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 706.","responses":[{"text":"Pectineus","correct":false,"visible":false},{"text":"Sartorius","correct":true,"visible":false},{"text":"Vastus medialis","correct":false,"visible":false},{"text":"Psoas major","correct":false,"visible":false},{"text":"Iliacus","correct":false,"visible":false}]},{"id":5357,"text":"Which of the following invaginates to form T-tubules?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 464.","responses":[{"text":"Terminal cisternae","correct":false,"visible":false},{"text":"Plasmalemma","correct":false,"visible":false},{"text":"Sarcolemma","correct":true,"visible":false},{"text":"Mitochondrial outer membrane","correct":false,"visible":false},{"text":"Sarcoplasmic reticulum","correct":false,"visible":false}]},{"id":5369,"text":"Which nerve is most likely to be damaged by a humeral shaft fracture distal to the deltoid tuberosity?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 213.","responses":[{"text":"Axillary nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":true,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false}]},{"id":5370,"text":"Which of the following embryonic layers is responsible for the formation of bones and cartilages?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 167.","responses":[{"text":"Intermediate mesoderm","correct":false,"visible":false},{"text":"Lateral plate mesoderm","correct":true,"visible":false},{"text":"Paraxial mesoderm","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"Ectoderm","correct":false,"visible":false}]},{"id":5371,"text":"Which of the following muscle pairs is involved in the abduction of the upper limb after the first 90 degrees of movement?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180. (2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 89.","responses":[{"text":"Deltoid and levator scapulae","correct":false,"visible":false},{"text":"Trapezius and levator scapulae","correct":false,"visible":false},{"text":"Trapezius and serratus anterior","correct":true,"visible":false},{"text":"Deltoid and supraspinatus","correct":false,"visible":false},{"text":"Deltoid and trapezius","correct":false,"visible":false}]},{"id":5423,"text":"Which action would fail in case of paralysis of the quadriceps femoris muscle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 584.","responses":[{"text":"Adduction at the hip","correct":false,"visible":false},{"text":"Extension at the knee","correct":true,"visible":false},{"text":"Extension of the hip","correct":false,"visible":false},{"text":"Flexion at the knee","correct":false,"visible":false},{"text":"Medial rotation of the knee","correct":false,"visible":false}]},{"id":5447,"text":"Which of the following statements is correct regarding the route of the great saphenous vein?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 655.","responses":[{"text":"Anterior to the medial malleolus","correct":true,"visible":false},{"text":"Joins the femoral vein superficial to the fascia lata","correct":false,"visible":false},{"text":"Anterior to the medial condyle of the tibia and femur","correct":false,"visible":false},{"text":"Passes up the lateral side of the leg","correct":false,"visible":false},{"text":"Posterior to the medial malleolus","correct":false,"visible":false}]},{"id":5470,"text":"What is the most common site for the fracture of a clavicle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 153.","responses":[{"text":"Junction of medial two third of a clavicle with lateral one third","correct":true,"visible":false},{"text":"The mid point of the clavicle","correct":false,"visible":false},{"text":"Junction of lateral three fourth of a clavicle with medial one fourth","correct":false,"visible":false},{"text":"Junction of medial three fourth of a clavicle with lateral one fourth","correct":false,"visible":false},{"text":"Junction of lateral two third of a clavicle with medial one third","correct":false,"visible":false}]},{"id":5471,"text":"Which of the following types of cells do Howship's lacunae contain?","explanation":"**Howship's lacunae** contain **osteoclasts**. These are specialized cells responsible for the resorption of bone tissue. Howship's lacunae are small pits on the surface of bone where osteoclasts are active. The osteoclasts attach to the bone surface and create an isolated environment where they can break down the bone matrix, releasing calcium and other minerals back into the bloodstream.\r\n\r\n---\r\n\r\nChondrocytes are cells that produce and maintain cartilage tissue.\r\nOsteoprogenitor cells are precursor cells that can differentiate into osteoblasts.\r\nOsteoblasts are cells responsible for bone formation.\r\nOsteocytes refer to mature bone cells that maintain the bone matrix.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 143.","responses":[{"text":"Osteoblasts","correct":false,"visible":false},{"text":"Osteocytes","correct":false,"visible":false},{"text":"Osteoprogenitor cells","correct":false,"visible":false},{"text":"Osteoclasts","correct":true,"visible":false},{"text":"Chondrocytes","correct":false,"visible":false}]},{"id":5472,"text":"Where are the cubital lymph nodes present?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 162.","responses":[{"text":"Just above the medial epicondyle","correct":true,"visible":false},{"text":"Just medial to the radial nerve","correct":false,"visible":false},{"text":"Just lateral to the brachial artery","correct":false,"visible":false},{"text":"At the medial border of the brachioradialis.","correct":false,"visible":false},{"text":"Just above the lateral epicondyle","correct":false,"visible":false}]},{"id":5473,"text":"What is true about Lambert-Eaton syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1226.","responses":[{"text":"Muscle weakness that worsens with use","correct":false,"visible":false},{"text":"Anticholinesterase agents improve symptoms","correct":false,"visible":false},{"text":"Autoantibodies against presynaptic calcium channels","correct":true,"visible":false},{"text":"Autoantibodies against postsynaptic acetylcholine receptors","correct":false,"visible":false},{"text":"Classically involves the eyes","correct":false,"visible":false}]},{"id":5474,"text":"What effect does myasthenia gravis have on deep tendon reflexes?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 484.","responses":[{"text":"Hyperreflexia occurs after exertion","correct":false,"visible":false},{"text":"Hyporeflexia is observed","correct":false,"visible":false},{"text":"Hyperreflexia is observed","correct":false,"visible":false},{"text":"Deep tendon reflexes are normal","correct":true,"visible":false},{"text":"Deep tendon reflexes are diminished","correct":false,"visible":false}]},{"id":5483,"text":"Which of the following veins pass through the deltopectoral triangle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 688.","responses":[{"text":"Axillary vein","correct":false,"visible":false},{"text":"Cephalic vein","correct":true,"visible":false},{"text":"Basilic vein","correct":false,"visible":false},{"text":"Brachial vein","correct":false,"visible":false},{"text":"Subclavian vein","correct":false,"visible":false}]},{"id":5484,"text":"To which of the following structures does the flexor retinaculum attach medially?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 783.","responses":[{"text":"Tubercle of scaphoid and ridge of trapezium","correct":false,"visible":false},{"text":"Pisiform and trapezoid","correct":false,"visible":false},{"text":"Hook of hamate and pisiform","correct":true,"visible":false},{"text":"Ridge of trapezium and hook of hamate","correct":false,"visible":false},{"text":"Tubercle of scaphoid and hook of hamate","correct":false,"visible":false}]},{"id":5485,"text":"Which of the following veins combine to form the axillary vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 188.","responses":[{"text":"Brachial vein and cephalic vein","correct":false,"visible":false},{"text":"Basilic vein and radial vein","correct":false,"visible":false},{"text":"Basilic vein and subclavian vein","correct":false,"visible":false},{"text":"Basilic vein and brachial vein","correct":true,"visible":false},{"text":"Basilic vein and cephalic vein","correct":false,"visible":false}]},{"id":5486,"text":"Which of the following is incorrect regarding the lamellae of bone?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 145, 147.","responses":[{"text":"Osteoblasts lie within the lamellae","correct":true,"visible":false},{"text":"Osteoclasts lie within lacunae","correct":false,"visible":false},{"text":"Lamellae of woven bone are irregular","correct":false,"visible":false},{"text":"Osteoblasts lie in between the lamellae","correct":false,"visible":false},{"text":"Lamellae are parallel to each other","correct":false,"visible":false}]},{"id":5487,"text":"Which of the following ligaments would be damaged if the tibia is dislocated posteriorly?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 607.","responses":[{"text":"Posterior cruciate ligament","correct":true,"visible":false},{"text":"Medial meniscus","correct":false,"visible":false},{"text":"Anterior cruciate ligament","correct":false,"visible":false},{"text":"Tibial collateral ligament","correct":false,"visible":false},{"text":"Lateral meniscus","correct":false,"visible":false}]},{"id":5488,"text":"Which of the following pair of joints is involved in the inversion and eversion of the foot?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 10.","responses":[{"text":"Subtalar and talocrural joint","correct":false,"visible":false},{"text":"Subtalar and transverse tarsal joint","correct":true,"visible":false},{"text":"Talotibial and talocalcanial","correct":false,"visible":false},{"text":"Talocrural and talocalcanial joint","correct":false,"visible":false},{"text":"Transverse tarsal and tibiotalar joint","correct":false,"visible":false}]},{"id":5489,"text":"Which of the following is the keystone of the medial longitudinal arch of the foot?","explanation":"The **talus head** is the keystone of the **medial longitudinal arch** of the foot. The medial longitudinal arch is composed of the calcaneus, talus, navicular, three cuneiforms, and three metatarsals. The talar head serves as the central point around which the arch is formed and provides crucial support to the structure of the foot. The tibialis anterior and posterior muscles, via their tendinous attachments, also help in supporting this arch.","reference":"Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 228.","responses":[{"text":"Medial cuneiform bone","correct":false,"visible":false},{"text":"Metatarsals","correct":false,"visible":false},{"text":"Calcaneal tubercle","correct":false,"visible":false},{"text":"Navicular bone","correct":false,"visible":false},{"text":"Talus head","correct":true,"visible":false}]},{"id":5490,"text":"Which muscle divides the axillary artery into three parts?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 722.","responses":[{"text":"Teres major","correct":false,"visible":false},{"text":"Coracobrachialis","correct":false,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Pectoralis minor","correct":true,"visible":false},{"text":"Teres minor","correct":false,"visible":false}]},{"id":5498,"text":"What are the indentations of the sarcolemma called?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 464.","responses":[{"text":"Pilli","correct":false,"visible":false},{"text":"Terminal cisternae","correct":false,"visible":false},{"text":"T-tubules","correct":true,"visible":false},{"text":"Sarcoplasmic reticulum","correct":false,"visible":false},{"text":"Lamellae","correct":false,"visible":false}]},{"id":5502,"text":"Which of the following wraps individual skeletal muscle fiber?","explanation":null,"reference":"Endomysium - an overview | sciencedirect topics. Accessed July 11, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/endomysium#","responses":[{"text":"Perimysium","correct":false,"visible":false},{"text":"Sarcoplasmic reticulum","correct":false,"visible":false},{"text":"Terminal cisternae","correct":false,"visible":false},{"text":"Endomysium","correct":true,"visible":false},{"text":"Epimysium","correct":false,"visible":false}]},{"id":5507,"text":"Damage to which of the following nerves is the most common cause of a foot drop?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 764.","responses":[{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":true,"visible":false},{"text":"Superficial fibular nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Saphenous nerve","correct":false,"visible":false}]},{"id":5513,"text":"What is true regarding Dupuytren's contracture?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 258.","responses":[{"text":"Caused by fibrous degeneration on radial side of the palmar aponeurosis","correct":false,"visible":false},{"text":"Caused by fibrous degeneration on ulnar side of the palmar aponeurosis","correct":true,"visible":false},{"text":"It causes flexion of 1st digit at metacarpophalangeal joint","correct":false,"visible":false},{"text":"It causes extension of 4th and 5th digits at metacarpophalangeal joint","correct":false,"visible":false},{"text":"Is a disease of interphalangeal joints of thumb","correct":false,"visible":false}]},{"id":5516,"text":"Which of the following is not a part of the anterior compartment of the arm?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 201, 204, 206.","responses":[{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":true,"visible":false},{"text":"Biceps brachii","correct":false,"visible":false},{"text":"Brachial artery","correct":false,"visible":false},{"text":"Coracobrachialis","correct":false,"visible":false}]},{"id":5517,"text":"Damage to which pair of nerves is responsible for loss of inversion of the foot?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 811.","responses":[{"text":"Deep peroneal and tibial nerve","correct":true,"visible":false},{"text":"Tibial and common peroneal nerve","correct":false,"visible":false},{"text":"Superficial peroneal and tibial nerve","correct":false,"visible":false},{"text":"Superficial peroneal and sural nerve","correct":false,"visible":false},{"text":"Superficial and deep peroneal nerve","correct":false,"visible":false}]},{"id":5518,"text":"A football player gets hit on the lateral aspect of his knee joint, resulting in a fracture of the neck of the fibula. Which of the following nerves is most likely to be injured in this case?","explanation":"In the case of a fracture of the **neck of the fibula**, the nerve most likely to be injured is the **common peroneal nerve** (also known as the common fibular nerve). This nerve wraps around the neck of the fibula and is susceptible to injury in fractures involving this area.\r\n\r\n---\r\n\r\nThe superficial fibular nerve is a branch of the common peroneal nerve, that supplies the lateral compartment of the leg.\r\nThe sciatic nerve is a large nerve originating from the lumbar and sacral plexus and splits into the tibial and common peroneal nerves.\r\nThe deep fibular nerve is another branch of the common peroneal nerve, that supplies the anterior compartment of the leg.\r\nThe tibial nerve is a branch of the sciatic nerve, that supplies the posterior compartment of the leg.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 542.","responses":[{"text":"Superficial fibular nerve","correct":false,"visible":false},{"text":"Common peroneal nerve","correct":true,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Deep fibular nerve","correct":false,"visible":false}]},{"id":5520,"text":"What is the root value of the common fibular nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 745.","responses":[{"text":"L5 to S2","correct":false,"visible":false},{"text":"L5 to S4","correct":false,"visible":false},{"text":"L2 to S4","correct":false,"visible":false},{"text":"L4 to S2","correct":true,"visible":false},{"text":"L2 to L4","correct":false,"visible":false}]},{"id":5521,"text":"Which of the following neurotransmitters is deficient in myasthenia gravis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 484.","responses":[{"text":"None of these","correct":true,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false}]},{"id":5544,"text":"Which of the following arteries does not supply the knee joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 746.","responses":[{"text":"Lateral femoral circumflex artery","correct":false,"visible":false},{"text":"Popliteal artery","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false},{"text":"Anterior tibial artery","correct":false,"visible":false},{"text":"Inferior gluteal artery","correct":true,"visible":false}]},{"id":5545,"text":"Which test is used to diagnose myasthenia gravis?","explanation":null,"reference":"Rousseff RT. Diagnosis of myasthenia gravis. Journal of Clinical Medicine. Published April 16, 2021. Accessed July 11, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8073361/","responses":[{"text":"Computed tomography scan","correct":false,"visible":false},{"text":"Romberg test","correct":false,"visible":false},{"text":"Electromyography","correct":true,"visible":false},{"text":"Pinprick test","correct":false,"visible":false},{"text":"Nerve conduction test","correct":false,"visible":false}]},{"id":5546,"text":"Which of the following nerves will be damaged by the fracture of a neck of the humerus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 693.","responses":[{"text":"Median nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":true,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false}]},{"id":5561,"text":"Which nerve brings about the flexion of the forearm?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 720.","responses":[{"text":"Radial nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":true,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Lateral cutaneous nerve of the forearm","correct":false,"visible":false}]},{"id":5562,"text":"Which of the following is the most important stabilizer of the shoulder joint?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 695.","responses":[{"text":"Deltoid muscle","correct":false,"visible":false},{"text":"Teres major muscle","correct":false,"visible":false},{"text":"Trapezius muscle","correct":false,"visible":false},{"text":"Pectoralis major muscle","correct":false,"visible":false},{"text":"Rotator cuff muscles","correct":true,"visible":false}]},{"id":5563,"text":"Which muscle prevents nerve damage from the broken ends of the clavicle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 169.","responses":[{"text":"Trapezius","correct":false,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Sternocleidomastoid","correct":false,"visible":false},{"text":"Subclavius","correct":true,"visible":false}]},{"id":5564,"text":"Which of the following pairs of nerves supply the lumbricals?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 799.","responses":[{"text":"Radial and ulnar nerve","correct":false,"visible":false},{"text":"Median and musculocutaneous nerve","correct":false,"visible":false},{"text":"Median and ulnar nerve","correct":true,"visible":false},{"text":"Median and radial nerve","correct":false,"visible":false},{"text":"Ulnar and musculocutaneous nerve","correct":false,"visible":false}]},{"id":5565,"text":"Which hormone is released when plasma calcium concentration increases?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 339.","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false},{"text":"Calcitonin","correct":true,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Vasopressin","correct":false,"visible":false}]},{"id":5566,"text":"What is the action of the serratus anterior on the scapula?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 716.","responses":[{"text":"Retraction","correct":false,"visible":false},{"text":"Downward rotation","correct":false,"visible":false},{"text":"Depression","correct":false,"visible":false},{"text":"Elevation","correct":false,"visible":false},{"text":"Protraction","correct":true,"visible":false}]},{"id":5567,"text":"What is true regarding Erb's palsy?","explanation":null,"reference":"Chater M, Camfield P, Camfield C. Erb’s palsy – Who is to blame and what will happen? Paediatr Child Health. 2004;9(8):556-560. Accessed July 11, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2724163/","responses":[{"text":"Abducted shoulder","correct":false,"visible":false},{"text":"C3-C5 nerve roots are involved","correct":false,"visible":false},{"text":"Flexed elbow","correct":false,"visible":false},{"text":"Policeman's tip hand","correct":true,"visible":false},{"text":"Laterally rotated arm","correct":false,"visible":false}]},{"id":5568,"text":"Which muscle is responsible for the inversion of the foot?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 625.","responses":[{"text":"Flexor digitorum longus","correct":false,"visible":false},{"text":"Fibularis tertius","correct":false,"visible":false},{"text":"Fibularis longus","correct":false,"visible":false},{"text":"Tibialis anterior","correct":true,"visible":false},{"text":"Fibularis brevis","correct":false,"visible":false}]},{"id":5569,"text":"Which of the following muscles is responsible for the lateral rotation and flexion of the thigh at the hip joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 704, 723, 729.","responses":[{"text":"Sartorius","correct":true,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Vastus lateralis","correct":false,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Gracilis","correct":false,"visible":false}]},{"id":5570,"text":"Which of the following is associated with Klumpke's palsy?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 200.","responses":[{"text":"Hand of benediction","correct":false,"visible":false},{"text":"Shoulder drop","correct":false,"visible":false},{"text":"Wrist drop","correct":false,"visible":false},{"text":"Claw hand","correct":true,"visible":false},{"text":"Waitor's tip hand","correct":false,"visible":false}]},{"id":5571,"text":"Which pair of muscles form the superomedial boundary of the popliteal fossa?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 609-610.","responses":[{"text":"Quadratus femoris and semitendinosus","correct":false,"visible":false},{"text":"Semimembranosus and semitendinosus","correct":true,"visible":false},{"text":"Semimembranosus and the lateral head of gastrocnemius","correct":false,"visible":false},{"text":"Semimembranosus and biceps femoris","correct":false,"visible":false},{"text":"Semitendinosus and biceps femoris","correct":false,"visible":false}]},{"id":5572,"text":"Which muscle unlocks the knee joint?","explanation":"The muscle that **unlocks the knee joint** is the **popliteus**. This muscle is responsible for initiating the flexion of the knee, allowing the leg to bend after it has been fully extended.\r\n\r\n\r\nGastrocnemius is primarily involved in plantar flexion of the ankle and also assists in knee flexion.\r\n\r\nThe plantaris is a small muscle that also assists in knee flexion and plantar flexion of the ankle.\r\n\r\nQuadriceps femoris is a group of muscles that are primarily responsible for knee extension, not for unlocking the knee.\r\n\r\nThe biceps femoris is one of the hamstring muscles, and it is involved in knee flexion and hip extension but does not unlock the knee joint.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 618.","responses":[{"text":"Quadriceps femoris","correct":false,"visible":false},{"text":"Popliteus","correct":true,"visible":false},{"text":"Plantaris","correct":false,"visible":false},{"text":"Gastrocnemius","correct":false,"visible":false},{"text":"Biceps femoris","correct":false,"visible":false}]},{"id":5573,"text":"Damage to which nerve presents as the claw hand?","explanation":"Damage to the **ulnar nerve** often presents as the **\"claw hand\"** deformity. This occurs because the ulnar nerve innervates the intrinsic muscles of the hand, and its dysfunction leads to an imbalance between the flexors and extensors, resulting in the characteristic clawing of the fingers.\r\n\r\n---\r\n\r\nAxillary nerve: Damage to this nerve typically affects the deltoid muscle and results in difficulty abducting the arm, not in a claw hand deformity.\r\n  \r\nMedian nerve: Damage to the median nerve can result in \"ape hand\" deformity or carpal tunnel syndrome but not the claw hand.\r\n  \r\nMusculocutaneous nerve: Damage to this nerve affects the muscles in the anterior compartment of the arm, leading to weakness in elbow flexion and forearm supination, not a claw hand.\r\n  \r\nRadial nerve: Damage to the radial nerve can result in \"wrist drop,\" where the wrist and fingers cannot be actively extended, but it does not result in a claw hand.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 239.","responses":[{"text":"Axillary nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":true,"visible":false}]},{"id":5574,"text":"Marble bone is a characteristic feature of which of the following diseases?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n1187.","responses":[{"text":"Osteonecrosis","correct":false,"visible":false},{"text":"Osteomalacia","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Osteopetrosis","correct":true,"visible":false},{"text":"Osteoarthritis","correct":false,"visible":false}]},{"id":5575,"text":"Which of the following muscles attaches to the nuchal ligament?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 91.","responses":[{"text":"Rhomboid major","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Levator scapulae","correct":false,"visible":false},{"text":"Rhomboid minor","correct":true,"visible":false}]},{"id":5576,"text":"Which of the following indicates chronic arthritis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 1008.","responses":[{"text":"Appearance of joint mice in an X-ray","correct":false,"visible":false},{"text":"Fibrillation of the cartilage","correct":true,"visible":false},{"text":"Decrease in proteoglycans of the matrix","correct":false,"visible":false},{"text":"Proteolytic breakdown of cartilage","correct":false,"visible":false},{"text":"Proliferation of chondrocytes","correct":false,"visible":false}]},{"id":5597,"text":"Which nerve supplies the skin of the medial one and half digits and the palm?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 807.","responses":[{"text":"Recurrent branch of the median nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Superficial branch of the ulnar nerve","correct":true,"visible":false},{"text":"Deep branch of the ulnar nerve","correct":false,"visible":false},{"text":"Palmar cutaneous branch of the median nerve","correct":false,"visible":false}]},{"id":5612,"text":"Which of the following nerves passes through pronator teres?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 758.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Median nerve","correct":true,"visible":false}]},{"id":5615,"text":"Which of the following drugs is a cyclooxygenase-1 and cyclooxygenase-2 inhibitor?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 498.","responses":[{"text":"Paracetamol","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Antipyrine","correct":false,"visible":false},{"text":"Dipyrone","correct":false,"visible":false}]},{"id":5642,"text":"Which of the following muscles is likely to be paralyzed if the suprascapular notch gets calcified?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 706, 707.","responses":[{"text":"Infraspinatus","correct":true,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Pectolaris major","correct":false,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":5712,"text":"Which of the following disrupts the absorption of calcium?","explanation":null,"reference":"Gupta RK, Gangoliya SS, Singh NK. Reduction of phytic acid and enhancement of bioavailable micronutrients in food grains. Journal of Food Science and Technology. Published February 2015. Accessed July 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4325021/","responses":[{"text":"Dihydrate","correct":false,"visible":false},{"text":"Calcium citrate","correct":false,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Calcium carbonate","correct":false,"visible":false},{"text":"Phytic acid","correct":true,"visible":false}]},{"id":5713,"text":"Which of the following has the highest percentage of element calcium?","explanation":null,"reference":"Sunyecz JA. The use of calcium and vitamin D in the management of osteoporosis. Ther Clin Risk Manag. 2008;4(4):827-836. Accessed July 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2621390/","responses":[{"text":"Calcium carbonate","correct":true,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Phytic acid","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Calcium citrate","correct":false,"visible":false}]},{"id":5714,"text":"Which of the following represents another name for Colles' fracture?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 155-156.","responses":[{"text":"Dinner fork deformity","correct":true,"visible":false},{"text":"Barton fracture","correct":false,"visible":false},{"text":"Smith's fracture","correct":false,"visible":false},{"text":"Monteggia fracture","correct":false,"visible":false},{"text":"Ape hand","correct":false,"visible":false}]},{"id":5715,"text":"Which of the following is the reason for Colle's fracture presenting in elderly patients?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 155.","responses":[{"text":"Parkinson","correct":false,"visible":false},{"text":"Osteoporosis","correct":true,"visible":false},{"text":"Osteopetrosis","correct":false,"visible":false},{"text":"Alzheimer's","correct":false,"visible":false},{"text":"Osteogenesis imperfecta","correct":false,"visible":false}]},{"id":5716,"text":"Which of the following is the most common radial fracture?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 155.","responses":[{"text":"Galeazzi fracture","correct":false,"visible":false},{"text":"Barton fracture","correct":false,"visible":false},{"text":"Monteggia fracture","correct":false,"visible":false},{"text":"Smith's fracture","correct":false,"visible":false},{"text":"Colle's fracture","correct":true,"visible":false}]},{"id":5717,"text":"Which of the following terms is used for the fusion of two or more digits?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 175.","responses":[{"text":"Brachydactyly","correct":false,"visible":false},{"text":"Synpolydactyly","correct":false,"visible":false},{"text":"Polydactyly","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Syndactyly","correct":true,"visible":false}]},{"id":5718,"text":"Which of the following is an example of a natural narcotic analgesic?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 191,192.","responses":[{"text":"Methadone","correct":false,"visible":false},{"text":"Codeine","correct":true,"visible":false},{"text":"Pethidine","correct":false,"visible":false},{"text":"Meperidine","correct":false,"visible":false},{"text":"Tramadol","correct":false,"visible":false}]},{"id":5719,"text":"Which of the following is inappropriate for leflunomide?","explanation":null,"reference":"(1) Padda IS, Goyal A. Leflunomide. In: StatPearls. StatPearls Publishing; 2022. Accessed July 9, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557799/\r\n\r\n(2) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 519.\r\n\r\n(3) Keen HI, Conaghan PG, Tett SE. Safety evaluation of leflunomide in rheumatoid arthritis. Expert Opinion on Drug Safety. Published July 2013. https://pubmed.ncbi.nlm.nih.gov/23668332/","responses":[{"text":"Prodrug","correct":false,"visible":false},{"text":"Hepatotoxic","correct":false,"visible":false},{"text":"Short lifetime","correct":true,"visible":false},{"text":"Alopecia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5720,"text":"Which of the following muscles is not involved in the plantarflexion?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 615, 625.","responses":[{"text":"Gastrocnemius","correct":false,"visible":false},{"text":"Soleus","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Peroneus tertius","correct":true,"visible":false},{"text":"Plantaris","correct":false,"visible":false}]},{"id":5721,"text":"Which of the following can be calculated by the standard deviation of the mean?","explanation":null,"reference":"Lee DK, In J, Lee S. Standard deviation and standard error of the mean. Korean Journal of Anesthesiology. Published June 2015. Accessed September 15, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4452664/","responses":[{"text":"Confidence interval","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Median","correct":false,"visible":false},{"text":"Constant","correct":false,"visible":false},{"text":"Mean","correct":false,"visible":false}]},{"id":5722,"text":"Reiter's syndrome is not associated with which of the following?","explanation":null,"reference":"Reiter syndrome - an overview | sciencedirect topics. Accessed July 12, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/reiter-syndrome#","responses":[{"text":"Conjunctivitis","correct":false,"visible":false},{"text":"Cervicitis","correct":true,"visible":false},{"text":"Arthritis","correct":false,"visible":false},{"text":"Enteritis","correct":false,"visible":false},{"text":"Urethritis","correct":false,"visible":false}]},{"id":5723,"text":"What effect is physical damage to the body most likely to produce?","explanation":null,"reference":"Physical damage definition: 171 samples. Law Insider. Accessed July 12, 2022. https://www.lawinsider.com/dictionary/physical-damage","responses":[{"text":"Injury","correct":true,"visible":false},{"text":"Chronic disease","correct":false,"visible":false},{"text":"Tumor","correct":false,"visible":false},{"text":"Mental disorder","correct":false,"visible":false},{"text":"Disability","correct":false,"visible":false}]},{"id":5724,"text":"Which of the following is not included in conventional disease-modifying antirheumatic drugs (DMARDs)?","explanation":null,"reference":"Katzung BG, Masters SB, Trevor AJ. Basic \u0026 Clinical Pharmacology. 12th ed. Mc Graw Hill; 2012: 308.","responses":[{"text":"Acetaminophen","correct":true,"visible":false},{"text":"Methotrexate","correct":false,"visible":false},{"text":"Hydroxychloroquine","correct":false,"visible":false},{"text":"Sulfasalazine","correct":false,"visible":false},{"text":"Leflunomide","correct":false,"visible":false}]},{"id":5725,"text":"Which of the following refers to the actions taken to prevent the injury before it occurs?","explanation":null,"reference":"Primary, secondary and tertiary prevention. Accessed July 12, 2022. https://www.iwh.on.ca/what-researchers-mean-by/primary-secondary-and-tertiary-prevention#","responses":[{"text":"Tertiary prevention","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Primordial prevention","correct":false,"visible":false},{"text":"Secondary prevention","correct":false,"visible":false},{"text":"Primary prevention","correct":true,"visible":false}]},{"id":5726,"text":"In an anteroposterior view of X-ray, a sesamoid bone is found in which digit?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 632-633.","responses":[{"text":"Distal portion of second metatarsal","correct":false,"visible":false},{"text":"Coronoid process of ulna","correct":false,"visible":false},{"text":"Lunate bone of wrist","correct":false,"visible":false},{"text":"Proximal portion of first metacarpal","correct":false,"visible":false},{"text":"Distal portion of first metacarpal","correct":true,"visible":false}]},{"id":5727,"text":"Which of the following is called a non-proliferative lesion of the epithelium of the breast?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 673.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Ductal epithelial hyperplasia","correct":false,"visible":false},{"text":"Fibrocystic changes","correct":true,"visible":false},{"text":"Lobular hyperplasia","correct":false,"visible":false},{"text":"Papilloma","correct":false,"visible":false}]},{"id":5728,"text":"Which of the following breast diseases is associated with diabetes?","explanation":null,"reference":"Campos GCP, Castro MVK e, de Mattos VFE, Pinto LZF e, Boechat MCB, dos Santos AASMD. Lymphocytic mastopathy mimicking breast malignancy: a case report. Radiologia Brasileira. Published 2014. Accessed July 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4337124/","responses":[{"text":"Benign lumps","correct":false,"visible":false},{"text":"Lymphocytic mastopathy","correct":true,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Mastitis","correct":false,"visible":false},{"text":"Gynecomastia","correct":false,"visible":false}]},{"id":5729,"text":"Which of the following fibers is slowest?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 591.","responses":[{"text":"C fiber","correct":true,"visible":false},{"text":"A beta fiber","correct":false,"visible":false},{"text":"A delta fiber","correct":false,"visible":false},{"text":"B fiber","correct":false,"visible":false},{"text":"A alpha fiber","correct":false,"visible":false}]},{"id":5773,"text":"Which of the following is the neurotransmitter that is released from neuromuscular junctions and causes the opening of ion channels that causes depolarization of the muscle fiber?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 93.","responses":[{"text":"Serotonin","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Glutamine","correct":false,"visible":false},{"text":"Acetylcholine","correct":true,"visible":false}]},{"id":5790,"text":"Which of the following neurotransmitters is released at cholinergic receptors?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 766.","responses":[{"text":"Glutamate","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Substance P","correct":false,"visible":false},{"text":"Acetylcholine","correct":true,"visible":false}]},{"id":5791,"text":"Which of the following is the most common bone disease?","explanation":null,"reference":"Sözen T, Özışık L, Başaran NÇ. An overview and management of osteoporosis. European Journal of Rheumatology. Published March 2017. Accessed July 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5335887/","responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Osteogenesis imperfecta","correct":false,"visible":false},{"text":"Osteoporosis","correct":true,"visible":false},{"text":"Achondroplasia","correct":false,"visible":false},{"text":"Melorheostosis","correct":false,"visible":false}]},{"id":5792,"text":"Which of the following signifies the action of Botulinum toxin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 96.","responses":[{"text":"Blocks the release of acetylcholine","correct":true,"visible":false},{"text":"Blocks the uptake of acetylcholine","correct":false,"visible":false},{"text":"Decreases the formation of acetylcholine","correct":false,"visible":false},{"text":"Increases the release of acetylcholine","correct":false,"visible":false},{"text":"Breaks down the acetylcholine","correct":false,"visible":false}]},{"id":5793,"text":"Posterior medial dislocation of the head of the femur damages which of the following nerves?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 557.","responses":[{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":true,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false}]},{"id":5794,"text":"Which of the following is correct for the double-blind method in randomized control trials?","explanation":null,"reference":"Randomised trials. Cancer Research UK. Published October 21, 2014. Accessed July 13, 2022. https://www.cancerresearchuk.org/about-cancer/find-a-clinical-trial/what-clinical-trials-are/randomised-trials","responses":[{"text":"Doctor knows about the drug given but the patient doesn't","correct":false,"visible":false},{"text":"Doctor, patient and the administer do not know about the drug","correct":false,"visible":false},{"text":"Both the doctor and the patient don't know about the drug","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Doctor and the patient don't know about the drug but the administer does","correct":false,"visible":false}]},{"id":5795,"text":"Which of the following hormones is responsible for breast development in the last trimester?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1036.","responses":[{"text":"Human chorionic gonadotropin","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Progesterone","correct":true,"visible":false}]},{"id":5796,"text":"What is the root value of the brachial plexus in a postfixed state?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 198.","responses":[{"text":"C2 to C5","correct":false,"visible":false},{"text":"C6 to T2","correct":true,"visible":false},{"text":"C5 to T1","correct":false,"visible":false},{"text":"T4 to T11","correct":false,"visible":false},{"text":"L4 to S5","correct":false,"visible":false}]},{"id":5797,"text":"Which of the following hormones is released by the suckling of the nipple by the baby?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 747.","responses":[{"text":"Estrogen","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Oxytocin","correct":true,"visible":false}]},{"id":5798,"text":"Which of the following is the function of the trapezius muscle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 703.","responses":[{"text":"Depression of the shoulders","correct":false,"visible":false},{"text":"Flexion of the neck","correct":false,"visible":false},{"text":"Extension of the neck","correct":false,"visible":false},{"text":"Rotation of the arm","correct":false,"visible":false},{"text":"Shrugging of the shoulders","correct":true,"visible":false}]},{"id":5803,"text":"Which of the following is correct for the mutation in the parathyroid hormone receptors?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1001-1002.","responses":[{"text":"Decrease in plasma concentration of calcium","correct":false,"visible":false},{"text":"Short term changes in plasma concentration of calcium","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Increase in plasma concentration of calcium","correct":false,"visible":false},{"text":"Long term changes in plasma concentration of calcium","correct":true,"visible":false}]},{"id":5804,"text":"Which of the following hormones is responsible for lactation at the end of pregnancy?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1057.","responses":[{"text":"Oxytocin","correct":false,"visible":false},{"text":"Prolactin","correct":true,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5805,"text":"Which of the following is the function of the parathyroid hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 360.","responses":[{"text":"Decreases calcium excretion","correct":true,"visible":false},{"text":"Increases calcium excretion","correct":false,"visible":false},{"text":"Decreases vitamin D levels","correct":false,"visible":false},{"text":"Increases calcium deposition in bone","correct":false,"visible":false},{"text":"Decreases phosphate excretion","correct":false,"visible":false}]},{"id":5806,"text":"Which of the following is the width of the synaptic cleft?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 574.","responses":[{"text":"20-30 nm","correct":true,"visible":false},{"text":"80-90 nm","correct":false,"visible":false},{"text":"90-100 nm","correct":false,"visible":false},{"text":"60-70 nm","correct":false,"visible":false},{"text":"40-60 nm","correct":false,"visible":false}]},{"id":5807,"text":"Which of the following is not a feature of cardiac muscle?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 113.","responses":[{"text":"Has myoglobin","correct":false,"visible":false},{"text":"High glycogen granules","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Well-developed mitochondria","correct":false,"visible":false},{"text":"Loose myofibril arrangement","correct":true,"visible":false}]},{"id":5808,"text":"Which of the following is not a part of the quadriceps femoris?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 581.","responses":[{"text":"Vastus medialis","correct":false,"visible":false},{"text":"Rectus femoris","correct":false,"visible":false},{"text":"Vastus intermedius","correct":false,"visible":false},{"text":"Vastus lateralis","correct":false,"visible":false},{"text":"Biceps femoris","correct":true,"visible":false}]},{"id":5809,"text":"Which nerve is subject to injury in a fracture of the midshaft of the humerus?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 213.","responses":[{"text":"Median nerve","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":true,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false}]},{"id":5816,"text":"A 12-year-old boy presents to the emergency department after a road traffic accident. On examination, the child does not seem to suffer any severe injuries on the outside but is unable to extend his knee. Which of the following nerves supplies the extensors of the knee?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 576.","responses":[{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Fibular nerve","correct":false,"visible":false},{"text":"Femoral nerve","correct":true,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false}]},{"id":5817,"text":"Which of the following is not a stage for health promotion and education?","explanation":null,"reference":"Ilyas M. Public Health and Community Medicine. 7th ed. Time Publishers; 2006: 352.","responses":[{"text":"Legislation","correct":true,"visible":false},{"text":"Sensitization","correct":false,"visible":false},{"text":"Education","correct":false,"visible":false},{"text":"Community transformation","correct":false,"visible":false},{"text":"Publicity","correct":false,"visible":false}]},{"id":5819,"text":"Cyclones are classified as which type of disasters?","explanation":"Cyclones are classified as **meteorological disasters**. They are natural events that occur due to atmospheric and weather conditions.\r\n\r\n---\r\n\r\nTelluric and tectonic are terms that are generally associated with geological phenomena like earthquakes and volcanic eruptions, not cyclones.\r\n\r\nAn atomic explosion would be a man-made or anthropogenic disaster, not a natural meteorological event like a cyclone.\r\n\r\nTopological is not a term typically used to classify types of disasters. It is more commonly associated with the study of geometric properties and spatial relations.\r\n\r\nAccidents refer to unplanned events that result in harm or damage but are not natural disasters like cyclones.","reference":"Wang Y, Xiao F, Zhang L, Gong Z. Research on evaluation of meteorological disaster governance capabilities in mainland china based on generalized λ-shapley choquet integral. International Journal of Environmental Research and Public Health. Published April 12, 2021. Accessed August 12, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8069057/","responses":[{"text":"Meteorological","correct":true,"visible":false},{"text":"Accident","correct":false,"visible":false},{"text":"Telluric and tectonic","correct":false,"visible":false},{"text":"Atomic explosion","correct":false,"visible":false},{"text":"Topological","correct":false,"visible":false}]},{"id":5820,"text":"Which of the following is the side effect of methotrexate?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 448.","responses":[{"text":"Ototoxicity","correct":false,"visible":false},{"text":"Myelosuppression","correct":true,"visible":false},{"text":"Pulmonary fibrosis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Anaphylactic reaction","correct":false,"visible":false}]},{"id":5822,"text":"Which of the following is the side effect of leflunomide?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 519.","responses":[{"text":"Cytotoxicity","correct":false,"visible":false},{"text":"Alopecia","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Ototoxicity","correct":false,"visible":false},{"text":"Nephrotoxicity","correct":false,"visible":false}]},{"id":5823,"text":"Which of the following is a side effect of glucocorticoid therapy?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 119.","responses":[{"text":"Exaggeration of inflammatory reaction","correct":false,"visible":false},{"text":"Osteoporosis","correct":true,"visible":false},{"text":"Alopecia","correct":false,"visible":false},{"text":"Ototoxicity","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5824,"text":"Hairline fractures occur in which of the following?","explanation":null,"reference":"Hairline fracture: Symptoms, treatment, and causes. Published October 26, 2017. Accessed July 13, 2022. https://www.medicalnewstoday.com/articles/319822","responses":[{"text":"Joints","correct":false,"visible":false},{"text":"Limbs","correct":true,"visible":false},{"text":"Mouth","correct":false,"visible":false},{"text":"Skull","correct":false,"visible":false},{"text":"Vertebrae","correct":false,"visible":false}]},{"id":5825,"text":"Which of the following is only an inhibitory neurotransmitter to the smooth muscle?","explanation":null,"reference":"Xue L, Farrugia G, Sarr MG, Szurszewski JH. ATP is a mediator of the fast inhibitory junction  potential in human jejunal circular smooth muscle. American Journal of Physiology-Gastrointestinal and Liver Physiology. Published June 1999. Accessed July 13, 2022. https://journals.physiology.org/doi/full/10.1152/ajpgi.1999.276.6.G1373","responses":[{"text":"Vasopressin","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Adenosine","correct":true,"visible":false}]},{"id":5826,"text":"What is the mechanism of action of curare?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 96.","responses":[{"text":"Stimulates cells in the anterior horn of the spinal cord","correct":false,"visible":false},{"text":"Prevents saltatory conduction of nerve impulses","correct":false,"visible":false},{"text":"Excites neuromuscular junctions","correct":false,"visible":false},{"text":"Slows conduction of nerve impulses","correct":false,"visible":false},{"text":"Inhibits motor nerve end-plates","correct":true,"visible":false}]},{"id":5827,"text":"Which of the following is the histological feature of ductal carcinoma in situ?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1057.","responses":[{"text":"Cellular polymorphism","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Hyperplasia","correct":false,"visible":false},{"text":"Necrosis","correct":true,"visible":false},{"text":"Fibrosis","correct":false,"visible":false}]},{"id":5828,"text":"At rest, the cell membrane is impermeable to which of the following ions?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 67.","responses":[{"text":"Ca++","correct":false,"visible":false},{"text":"Na+","correct":true,"visible":false},{"text":"P3-","correct":false,"visible":false},{"text":"K+","correct":false,"visible":false},{"text":"Cl-","correct":false,"visible":false}]},{"id":5829,"text":"Which of the following is true after treatment is initiated for a patient?","explanation":null,"reference":"Tweeddale MG. Grasping the nettle—what to do when patients withdraw their consent for treatment: (A clinical perspective on the case of ms b). Journal of Medical Ethics. Published August 1, 2002. Accessed July 14, 2022. https://jme.bmj.com/content/28/4/236","responses":[{"text":"Patient can not withdraw consent","correct":false,"visible":false},{"text":"Patient's consent is not taken","correct":false,"visible":false},{"text":"Patient can not leave the treatment","correct":false,"visible":false},{"text":"Patient is not allowed to take decisions","correct":false,"visible":false},{"text":"Patient can withdraw consent anytime","correct":true,"visible":false}]},{"id":5830,"text":"Which of the following is the largest protein in sarcomere?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"Myosin","correct":false,"visible":false},{"text":"Tropomodulin","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Actin","correct":false,"visible":false},{"text":"Titin","correct":true,"visible":false}]},{"id":5831,"text":"Which of the following is not included in seronegative spondyloarthropathies?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1213. (2) Sen R, Goyal A, Hurley JA. Seronegative spondyloarthropathy. In: StatPearls. StatPearls Publishing; 2022. Accessed July 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK459356/","responses":[{"text":"Reactive arthritis","correct":false,"visible":false},{"text":"Ankylosing spondylitis","correct":false,"visible":false},{"text":"Rheumatoid arthritis","correct":true,"visible":false},{"text":"Axial spondyloarthritis","correct":false,"visible":false},{"text":"Psoriatic arthritis","correct":false,"visible":false}]},{"id":6227,"text":"The Boltzmann equation is used to calculate membrane potential using which of the following?","explanation":null,"reference":"Barbosa NSV, Lima ERA, Boström M, Tavares FW. Membrane potential and ion partitioning in an erythrocyte using the poisson–boltzmann equation. The Journal of Physical Chemistry B. Published May 28, 2015. Accessed July 14, 2022. https://pubs.acs.org/doi/10.1021/acs.jpcb.5b02215","responses":[{"text":"Several different ions","correct":true,"visible":false},{"text":"Two different ions","correct":false,"visible":false},{"text":"Difference in ion concentration","correct":false,"visible":false},{"text":"One particular ion","correct":false,"visible":false},{"text":"Ion counter transport","correct":false,"visible":false}]}
]

